import { test, expect } from '@playwright/test';

test('Amazon SG - Search for gibberish and validate no results message', async ({ page }) => {
  // 1. Launch browser → Amazon SG.
  await page.goto('https://www.amazon.sg/');

  // 2. Search for "asdasd123!@#".
  const searchInput = page.locator('input#twotabsearchtextbox');
  await expect(searchInput).toBeVisible({ timeout: 10000 });
  await searchInput.fill('asdasd123!@#');
  await page.getByRole('button', { name: 'Go' }).click();

  // 3. Wait for results page.
  await expect(page).toHaveURL(/k=asdasd123!@#/i, { timeout: 15000 });

  // 4. Validate "no results" or limited results message appears.
  // Amazon SG may show: "No results for asdasd123!@#" or "did not match any products"
  // Try both possible messages.
  const noResults1 = page.getByText('No results for', { exact: false });
  const noResults2 = page.getByText('did not match any products', { exact: false });
  const noResults3 = page.getByText('We found 0 results for', { exact: false });

  const foundNoResults =
    (await noResults1.count()) > 0 ||
    (await noResults2.count()) > 0 ||
    (await noResults3.count()) > 0;

  expect(foundNoResults).toBeTruthy();

  // 5. Close browser.
  // (Playwright test runner handles browser closure automatically.)
});
